const body = $input.first().json.body || $input.first().json;
const event = body;
const subscription = event?.data?.object || {};

const cancellationReason = subscription.cancellation_details?.reason || '';
const isVoluntary = cancellationReason === 'cancellation_requested';

if (!isVoluntary) {
  return [{ json: { skip: true, reason: 'Not a voluntary cancellation', cancellationReason } }];
}

const customerId = subscription.customer || '';
const subscriptionId = subscription.id || '';
const cancelledAt = subscription.canceled_at
  ? new Date(subscription.canceled_at * 1000).toISOString()
  : new Date().toISOString();
const currentPeriodEnd = subscription.current_period_end
  ? new Date(subscription.current_period_end * 1000).toISOString()
  : null;
const accessEndDisplay = currentPeriodEnd
  ? new Date(currentPeriodEnd).toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
  : 'immediately';

// 7 days in seconds for Wait node
const winBackWaitSeconds = 7 * 24 * 60 * 60;

return [{ json: {
  customerId,
  subscriptionId,
  cancellationReason,
  cancelledAt,
  currentPeriodEnd,
  accessEndDisplay,
  winBackWaitSeconds,
  skip: false,
  updatedAt: new Date().toISOString(),
  rawPayload: JSON.stringify(body)
} }];

const users = $input.first().json;
const user = Array.isArray(users) ? users[0] : users;
const parsed = $('Parse Cancellation Payload').first().json;

const planTier = user?.plan_tier || 'starter';
const planDisplayNames = { free: 'Free', starter: 'Starter', pro: 'Pro', scale: 'Scale' };
const planDisplay = planDisplayNames[planTier] || planTier;

return [{ json: {
  ...parsed,
  email: user?.email || '',
  firstName: user?.first_name || 'there',
  planTier,
  planDisplay
} }];

